void solve(int CASE)
{
	int n, p, k; cin >> n >> p >> k;
	var a = vector<pair<ll, vector<ll>>>(n + 1);
	fa(i, 1, n)cin >> a[i].px;
	fa(i, 1, n) {
		var ve = vector<ll>(p);
		fa(j, 0, p - 1)cin >> ve[j];
		a[i].py = move(ve);
	}
	sort(all1(a), [](const var& a, const var& b)->bool {
		return a.px > b.px;
		});
	var dp = Vec2<ll>(n + 1, 1 << p);
	fa(i, 1, n) {
		const var& [x, y] = a[i];
		fa(s, 0, (1 << p) - 1) {
			int left = (i - 1) - popcnt(s);
			if (left < 0)continue;
			fa(j, 0, p - 1) {
				if (!(s & (1 << j))) {
					// 在 j 位置填上
					dp[i][s | (1 << j)] = max(dp[i][s | (1 << j)], dp[i - 1][s] + y[j]);
				}
			}
			if (left >= k)dp[i][s] = max(dp[i][s], dp[i - 1][s]);
			else dp[i][s] = max(dp[i][s], dp[i - 1][s] + x);
		}
	}
	cout << dp[n][(1 << p) - 1] << endl;
	return;
}
